import React, { useState } from "react";
import { fetchAppointmentsByPatient } from "../utils/api";
import "./AppointmentList.css";

export default function AppointmentList() {
  const [patientId, setPatientId] = useState("");
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");

  const handleChange = async (e) => {
    const value = e.target.value;
    setPatientId(value);
    setErr("");
    if (!value) {
      setAppointments([]);
      return;
    }

    setLoading(true);
    try {
      const data = await fetchAppointmentsByPatient(Number(value));
      setAppointments(data || []);
    } catch (error) {
      setErr(error?.message || "Failed to load appointments");
      setAppointments([]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <select
        data-testid="patient-filter"
        value={patientId}
        onChange={handleChange}
      >
        <option value="">Select patient</option>
        <option value="1">Patient 1</option>
        <option value="2">Patient 2</option>
      </select>

      {loading ? (
        <div>Loading appointments…</div>
      ) : err ? (
        <div className="field-error">{err}</div>
      ) : appointments.length === 0 ? (
        <div data-testid="no-appointments">No appointments</div>
      ) : (
        <ul>
          {appointments.map((a) => (
            <li key={a.id}>
              {a.reason} - {a.appointmentDate} {a.appointmentTime}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
